 import PostCard from "../components/PostCard";
import { useNavigate } from "react-router-dom";
import blogImg from "../assets/blog.png";
<Route path="/post/:id" element={<PostDetails />} />
import { Link } from "react-router-dom";

<Link to={`/post/${post.id}`}>
  <h2>{post.title}</h2>
</Link>

function Home() {
const navigate = useNavigate();

const posts = [
{
id: 1,
title: "MERN Stack Guide",
content: "Learn MERN stack from scratch and build full stack applications.",
author: "Kavya",
likes: 12,
comments: 5,
image: "https://images.unsplash.com/photo-1506744038136-46273834b3fb"
},
{
id: 2,
title: "React Tutorial",
content: "A complete guide to learn React step by step.",
author: "Admin",
likes: 8,
comments: 3,
image: "https://images.unsplash.com/photo-1633356122544-f134324a6cee"
},
{
id: 3,
title: "JavaScript Basics",
content: "Understand JavaScript fundamentals.",
author: "Suresh",
likes: 6,
comments: 2,
image: "https://images.unsplash.com/photo-1515879218367-8466d910aaa4"
}
];

return (
<> <section className="hero"> <div className="hero-content"> <h1>
Share Your Ideas.<br /> <span>Inspire the World.</span> </h1>
      <p>
        Join thousands of writers and readers sharing
        knowledge, stories and experiences.
      </p>

      <div className="hero-buttons">
        <button
          className="primary-btn"
          onClick={() => navigate("/register")}
        >
          Get Started
        </button>

        <button
          className="secondary-btn"
          onClick={() => navigate("/dashboard")}
        >
          Explore Blogs →
        </button>
      </div>
    </div>

    <div className="hero-image">
      <img
        src= {
          "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQzLR9IWGj6shCWMVoUe0YF5x7qMRnuQno9apNgmLkI6w&s=10"
        }
        alt="Blog Illustration"
      />
    </div>
  </section>

  <h2 className="section-title">
    Latest Blog Posts
  </h2>

  <div className="posts-grid">
    {posts.map((post) => (
      <PostCard
        key={post.id}
        post={post}
      />
    ))}
  </div>
   <div>
      {/* Search Bar */}
      <input
        type="text"
        placeholder="Search blogs..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />

      {/* Blog Cards */}
      {filteredPosts.length > 0 ? (
        filteredPosts.map((post) => (
          <div key={post.id} className="blog-card">
            <h2>{post.title}</h2>
            <p>{post.content}</p>
          </div>
        ))
      ) : (
        <h3>No blogs found</h3>
      )}
    </div>
</>

);
}

export default Home;
